#!/bin/bash# k3s-prod-audit.sh - Node-level audit scriptTS=$(date +%Y%m%d_%H%M%S)HN=$(hostname)OD="/tmp/audit-$HN-$TS"mkdir -p "$OD"echo "Audit: $HN at $TS"# 1. System Infouname -a > "$OD/system.txt"free -h >> "$OD/system.txt"# 2. K3s Statusif command -v k3s &> /dev/null; then    k3s --version > "$OD/k3s_version.txt"fisystemctl status k3s* --no-pager > "$OD/k3s_service.txt" 2>&1# 3. Certificatesif [ -d /var/lib/rancher/k3s/server/tls ]; then    find /var/lib/rancher/k3s/server/tls -name "*.crt" -exec sh -c 'echo "--- {} ---"; openssl x509 -enddate -noout -in {}' \; > "$OD/certs.txt"fi# 4. Storagedf -h > "$OD/disk.txt"mount | grep longhorn > "$OD/longhorn.txt"# 5. Networkingip addr > "$OD/net.txt"# 6. Registryif [ -f /etc/rancher/k3s/registries.yaml ]; then    cat /etc/rancher/k3s/registries.yaml | sed 's/password: .*/password: [REDACTED]/' > "$OD/registry.txt"fi# 7. Logsjournalctl -u k3s* -n 50 --no-pager > "$OD/logs.txt" 2>&1# PackageBP="/tmp/k3s-prod-audit-$HN-$TS.tar.gz"tar -czf "$BP" -C /tmp "audit-$HN-$TS"rm -rf "$OD"echo "BUNDLE:$BP"